 11→/**
 12→ * Compiler — Translates Lisp AST to C3 source code.
 13→ *
 14→ * The compiler generates C3 code that uses a minimal runtime library
 15→ * for value representation and function invocation.
 16→ *
 17→ * Region-based memory management:
 18→ * - Objects are allocated in regions
 19→ * - Closures track their home region
 20→ * - Write barriers mark objects as escaped when stored across regions
 21→ * - When a region dies, escaped objects are promoted to the parent
 22→ */
 23→struct Compiler {
 24→    Interp*     interp;          // For symbol table access
 25→    DString     output;          // Generated C3 code (dynamic string)
 26→    usz         indent;          // Current indentation level
 27→    usz         temp_counter;    // For generating unique temp names
 28→    usz         lambda_counter;  // For generating lambda function names
 29→
 30→    // Track captured variables for closure generation
 31→    List{SymbolId} current_captures;
 32→
 33→    // Track defined globals for forward declarations
 34→    List{SymbolId} defined_globals;
 35→
 36→    // Lambda definitions to emit after scanning
 37→    List{LambdaDef} lambda_defs;
 38→
 39→    // Track which lambdas create nested closures (for frame region optimization)
 40→    bool[256] lambda_creates_closure;
 41→
 42→    // Track mutable-captured variables (stored in interpreter env, not C3 locals)
 43→    List{SymbolId} mutable_captures;
 44→
 45→    // Track variables declared in current function scope (to avoid re-declaration/shadowing)
 46→    List{SymbolId} declared_vars;
 47→
 48→    // When true, emit rt_print_value for the last non-define expression
 49→    bool print_last;
 50→
 51→    // When true, emit rt_print_value for EVERY non-define expression
 52→    bool print_all;
 53→
 54→    // When true, find_free_vars uses is_builtin_primitive instead of is_primitive
 55→    // (for delegation contexts where user globals need injection into interpreter env)
 56→    bool for_delegation;
 57→
 58→    // Compiled modules: track module name → exported symbols
 59→    usz compiled_module_count;
 60→    usz compiled_module_capacity;
 61→    CompiledModule* compiled_modules;
 62→}
