378→fn bool is_c3_reserved(char[] name) {
379→    char[][*] reserved = {"try", "var", "fn", "if", "else", "for", "while", "do",
380→        "switch", "case", "default", "return", "break", "continue", "import",
381→        "module", "struct", "enum", "union", "const", "static", "true", "false",
382→        "null", "void", "bool", "int", "uint", "char", "float", "double", "usz"};
383→    foreach (r : reserved) {
384→        if (name.len == r.len) {
385→            bool match = true;
386→            for (usz i = 0; i < name.len; i++) {
387→                if (name[i] != r[i]) { match = false; break; }
388→            }
389→            if (match) return true;
390→        }
391→    }
392→    return false;
393→}
