423→/** Main entry point. */
424→fn int main(int argc, char** argv) {
425→    // Check for --help / -h flag
426→    for (int i = 1; i < argc; i++) {
427→        if (str_eq(argv[i], "--help") || str_eq(argv[i], "-h") || str_eq(argv[i], "-help")) {
428→            return print_help();
429→        }
430→    }
431→
432→    // Check for --version / -v flag
433→    for (int i = 1; i < argc; i++) {
434→        if (str_eq(argv[i], "--version") || str_eq(argv[i], "-v")) {
435→            io::printn("omni 0.1.5");
436→            return 0;
437→        }
438→    }
439→
440→    // Check for --init flag (scaffold new project)
441→    for (int i = 1; i < argc; i++) {
442→        if (str_eq(argv[i], "--init")) {
443→            return run_init(argc, argv, i);
444→        }
445→    }
446→
447→    // Check for --bind flag (generate FFI bindings)
448→    for (int i = 1; i < argc; i++) {
449→        if (str_eq(argv[i], "--bind")) {
450→            return run_bind(argc, argv, i);
451→        }
452→    }
453→
454→    // Check for --build flag (AOT compile to standalone binary)
455→    for (int i = 1; i < argc; i++) {
456→        if (str_eq(argv[i], "--build")) {
457→            return run_build(argc, argv, i);
458→        }
459→    }
460→
461→    // Check for compile flag
462→    bool run_compile = false;
463→    char* input_file = null;
464→    char* output_file = null;
465→    for (int i = 1; i < argc; i++) {
466→        if (str_eq(argv[i], "--compile") || str_eq(argv[i], "-compile")) {
467→            run_compile = true;
468→            if (i + 1 < argc) {
469→                input_file = argv[i + 1];
470→            }
471→            if (i + 2 < argc) {
472→                output_file = argv[i + 2];
473→            }
474→            break;
475→        }
476→    }
477→
478→    if (run_compile) {
479→        // Compile mode
480→        if (input_file == null || output_file == null) {
481→            io::printn("Usage: ./main --compile input.lisp output.c3");
482→            return 1;
483→        }
484→
485→        io::printfn("Compiling %s to %s...", (ZString)input_file, (ZString)output_file);
486→
487→        // Read input file
488→        char[] input_path;
489→        usz input_len = 0;
490→        char* p = input_file;
491→        while (*p != 0) { input_len++; p++; }
492→        input_path = input_file[:input_len];
493→
494→        if (try source = io::file::load_temp((String)input_path)) {
495→            // Initialize thread-local registry before interpreter
496→            thread_registry_init();
497→
498→            // Initialize interpreter for symbol table (heap-allocated due to size)
499→            lisp::Interp* interp = (lisp::Interp*)mem::malloc(lisp::Interp.sizeof);
500→            interp.init();
501→
502→            // Compile to C3
503→            char[] c3_code = lisp::compile_to_c3(source, interp);
504→
505→            // Write output file
506→            char[] output_path;
507→            usz output_len = 0;
508→            p = output_file;
509→            while (*p != 0) { output_len++; p++; }
510→            output_path = output_file[:output_len];
511→
512→            if (try file = io::file::open((String)output_path, "w")) {
513→                defer (void)file.close();
514→                file.write(c3_code)!!;
515→                io::printfn("Compilation successful: %s", (ZString)output_file);
516→                mem::free(interp);
517→                thread_registry_shutdown();
518→                return 0;
519→            } else {
520→                io::printfn("Error: cannot write output file %s", (ZString)output_file);
521→                mem::free(interp);
522→                thread_registry_shutdown();
523→                return 1;
524→            }
525→        } else {
526→            io::printfn("Error: cannot read input file %s", (ZString)input_file);
527→            return 1;
528→        }
529→    }
530→
531→    // Check for --gen-e2e flag
532→    for (int i = 1; i < argc; i++) {
533→        if (str_eq(argv[i], "--gen-e2e")) {
534→            thread_registry_init();
535→            lisp::Interp* interp = (lisp::Interp*)mem::malloc(lisp::Interp.sizeof);
536→            interp.init();
537→            lisp::register_primitives(interp);
538→
539→            lisp::register_stdlib(interp);
540→            interp.flags.jit_enabled = true;
541→
542→            lisp::generate_e2e_tests(interp);
543→
544→            mem::free(interp);
545→            thread_registry_shutdown();
546→            return 0;
547→        }
548→    }
549→
550→    // Check for REPL flag
551→    bool run_repl = false;
552→    for (int i = 1; i < argc; i++) {
553→        if (str_eq(argv[i], "-repl") || str_eq(argv[i], "--repl")) {
554→            run_repl = true;
555→            break;
556→        }
557→    }
558→
559→    if (run_repl) {
560→        // Start REPL mode
561→        io::printn("Starting Lisp REPL...");
562→
563→        // Initialize thread-local registry first
564→        thread_registry_init();
565→
566→        // Initialize interpreter
567→        lisp::Interp* interp = (lisp::Interp*)mem::malloc(lisp::Interp.sizeof);
568→        interp.init();
569→        lisp::register_primitives(interp);
570→        lisp::register_stdlib(interp);
571→        interp.flags.jit_enabled = true;
572→
573→        // Run REPL
574→        lisp::repl(interp);
575→
576→        // Clean up
577→        mem::free(interp);
578→        thread_registry_shutdown();
579→        return 0;
580→    }
581→
582→    // Check for script file argument (any arg that isn't a known flag)
583→    if (argc > 1) {
584→        // argv[1] is not --compile, -repl, or --repl — treat as script file
585→        char* script_file = argv[1];
586→        usz script_path_len = 0;
587→        char* sp = script_file;
588→        while (*sp != 0) { script_path_len++; sp++; }
589→        char[] script_path = script_file[:script_path_len];
590→
591→        // Read script file
592→        if (try source = io::file::load_temp((String)script_path)) {
593→            // Initialize thread-local registry
594→            thread_registry_init();
595→
596→            // Initialize interpreter
597→            lisp::Interp* interp = (lisp::Interp*)mem::malloc(lisp::Interp.sizeof);
598→            interp.init();
599→            lisp::register_primitives(interp);
600→
601→            lisp::register_stdlib(interp);
602→            interp.flags.jit_enabled = true;
603→
604→            // Push script directory for relative import resolution
605→            lisp::push_source_dir(script_path, interp);
606→
607→            // Run the script (multiple expressions)
608→            usz len = source.len;
609→            if (len > 65535) len = 65535;
610→            char[] src = source[:len];
611→            lisp::EvalResult r = lisp::run_program(src, interp);
612→
613→            if (r.error.has_error) {
614→                // Print error
615→                usz msg_len = 0;
616→                while (msg_len < 256 && r.error.message[msg_len] != 0) {
617→                    msg_len++;
618→                }
619→                if (r.error.line > 0) {
620→                    io::printf("Error at line %d, column %d: ", (int)r.error.line, (int)r.error.column);
621→                } else {
622→                    io::print("Error: ");
623→                }
624→                for (usz i = 0; i < msg_len; i++) {
625→                    io::printf("%c", r.error.message[i]);
626→                }
627→                io::printn("");
628→                mem::free(interp);
629→                thread_registry_shutdown();
630→                return 1;
631→            }
632→
633→            // Print result if non-nil
634→            if (r.value != null && !lisp::is_nil(r.value)) {
635→                lisp::print_value(r.value, &interp.symbols);
636→                io::printn("");
637→            }
638→
639→            mem::free(interp);
640→            thread_registry_shutdown();
641→            return 0;
642→        } else {
643→            io::printfn("Error: cannot read script file '%s'", (ZString)script_file);
644→            return 1;
645→        }
646→    }
647→
648→    // Run tests mode
649→    io::printfn("Region Memory System v3 initialized");
650→
651→    // Run stack engine tests (mmap stacks, context switch, coroutine lifecycle)
652→    run_stack_engine_tests();
653→
654→    // Run scope region tests (bump allocator, RC, freelist recycling)
655→    run_scope_region_tests();
656→
657→    // Initialize thread-local registry BEFORE Lisp tests (interpreter uses regions)
658→    thread_registry_init();
659→    io::printfn("Thread-local registry initialized, root id=%d", (uint)thread_registry().root_id);
660→
661→    // Run Lisp interpreter tests
662→    lisp::run_lisp_tests();
663→
664→    thread_registry_shutdown();
665→
666→    io::printfn("System ready.");
667→    return 0;
668→}
