  7→// =============================================================================
  8→// SECTION 1: VALUE REPRESENTATION
  9→// =============================================================================
 10→
 11→/**
 12→ * ValueTag — Type tag for runtime values.
 13→ */
 14→enum ValueTag : char {
 15→    V_NIL,
 16→    V_INT,
 17→    V_STRING,
 18→    V_SYMBOL,
 19→    V_CONS,
 20→    V_CLOSURE,
 21→    V_PRIM,
 22→    V_PRIM_UNARY, // Unary primitive (called immediately with one arg)
 23→    V_PARTIAL,    // Partially applied primitive (curried)
 24→    V_TRUE,       // Distinguished true value
 25→    V_FALSE,      // Distinguished false value
 26→    V_CONTINUATION, // Captured delimited continuation
 27→    V_FFI_HANDLE,   // FFI library handle (dlopen result)
 28→    V_THUNK,        // Suspended tail call (for TCO trampoline)
 29→    V_DOUBLE,       // Floating-point number
 30→    V_INTERP_REF,   // Opaque reference to interpreter Value* (for HASHMAP, ARRAY, etc.)
 31→    V_DICT,         // Native runtime hash map
 32→    V_ARRAY,        // Native runtime array
 33→}
 34→
 35→/**
 36→ * Closure function signature.
 37→ * Takes closure data pointer and argument, returns result.
 38→ */
 39→alias ClosureFn = fn Value(void* data, Value arg);
 40→
 41→/**
 42→ * Primitive function signature.
 43→ * Takes two arguments for binary operations (first may be null for unary).
 44→ */
 45→alias PrimFn = fn Value(Value a, Value b);
 46→
 47→/**
 48→ * StringData — Heap-allocated string storage.
 49→ * Allocated in regions.
 50→ */
 51→struct StringData {
 52→    char[4096] chars;
 53→    usz len;
 54→}
 55→
 56→// UTF-8 helpers for runtime strings
 57→fn usz rt_utf8_cplen(char c) {
 58→    uint b = (uint)c;
 59→    if (b < 0x80) { return 1; }
 60→    if (b < 0xC0) { return 1; }
 61→    if (b < 0xE0) { return 2; }
 62→    if (b < 0xF0) { return 3; }
 63→    if (b < 0xF8) { return 4; }
 64→    return 1;
 65→}
 66→
 67→fn usz rt_utf8_strlen(char[] bytes) {
 68→    usz count = 0;
 69→    usz pos = 0;
 70→    while (pos < bytes.len) {
 71→        pos += rt_utf8_cplen(bytes[pos]);
 72→        count++;
 73→    }
 74→    return count;
 75→}
 76→
 77→fn usz rt_utf8_byte_offset(char[] bytes, usz char_idx) {
 78→    usz pos = 0;
 79→    usz count = 0;
 80→    while (pos < bytes.len && count < char_idx) {
 81→        pos += rt_utf8_cplen(bytes[pos]);
 82→        count++;
 83→    }
 84→    return pos;
 85→}
