 87→/**
 88→ * ConsCell — Pair cell with region-based storage.
 89→ * car and cdr are handles to Value objects in some region.
 90→ */
 91→struct ConsCell {
 92→    main::ObjectHandle car;
 93→    main::ObjectHandle cdr;
 94→}
 95→
 96→/**
 97→ * ClosureData — Closure representation.
 98→ * The data pointer points to a closure struct allocated in a region.
 99→ */
100→struct ClosureData {
101→    void*               data;         // Captured environment struct (region-allocated)
102→    ClosureFn           invoke;       // Function pointer
103→    main::RegionHandle  home_region;  // Region where closure was created
104→    bool                is_variadic;  // True for variadic closures (receives arg list)
105→}
106→
107→/**
108→ * PartialData — Partially applied primitive.
109→ * first_arg is a handle to the first argument Value.
110→ */
111→struct PartialData {
112→    PrimFn              func;
113→    main::ObjectHandle  first_arg;  // Handle to first argument Value
114→}
115→
116→/**
117→ * Value — Tagged union for all runtime values.
118→ *
119→ * Design decisions:
120→ * - Immediates (int, nil, true) are stored inline
121→ * - Heap data (strings, symbols, cons cells) use ObjectHandles
122→ * - Closures track their home region for write barrier purposes
123→ */
124→struct Value {
125→    ValueTag tag;
126→
127→    union {
128→        long                int_val;      // V_INT - immediate
129→        main::ObjectHandle  str_handle;   // V_STRING - region-allocated StringData
130→        main::ObjectHandle  sym_handle;   // V_SYMBOL - region-allocated SymbolData
131→        ConsCell            cons_val;     // V_CONS - inline with handles to car/cdr
132→        ClosureData         closure_val;  // V_CLOSURE - inline closure data
133→        PrimFn              prim_val;     // V_PRIM - function pointer
134→        PartialData         partial_val;  // V_PARTIAL - inline partial application
135→        double              double_val;   // V_DOUBLE - floating-point
136→        void*               ffi_handle;   // V_FFI_HANDLE - dlopen handle
137→        ThunkData           thunk_val;    // V_THUNK - suspended tail call
138→        void*               interp_ref;   // V_INTERP_REF - opaque reference (bridge only)
139→        RtHashMap*          dict_val;     // V_DICT - native hash map
140→        RtArray*            array_val;    // V_ARRAY - native array
141→    }
142→}
143→
144→/**
145→ * ThunkData — Suspended tail call for TCO trampoline.
146→ * Instead of making a recursive call, emit a thunk that rt_invoke will bounce.
147→ * Arg is stored via ObjectHandle to avoid recursive Value definition.
148→ */
149→struct ThunkData {
150→    ClosureFn           invoke;  // Function to invoke
151→    void*               data;    // Closure data
152→    main::ObjectHandle  arg;     // Argument (region-allocated Value)
153→}
154→
155→/**
156→ * SymbolData — Heap-allocated symbol name storage.
157→ */
158→struct SymbolData {
159→    char[256] chars;
160→    usz len;
161→}
162→
163→/**
164→ * RtHashEntry — Key-value pair for native runtime hash map.
165→ */
166→struct RtHashEntry {
167→    Value key;    // key (V_NIL tag = empty slot)
168→    Value value;
169→}
170→
171→/**
172→ * RtHashMap — Open-addressing hash map with linear probing.
173→ * Self-contained, no interpreter dependency.
174→ */
175→struct RtHashMap {
176→    RtHashEntry* entries;
177→    uint capacity;
178→    uint count;
179→    uint mask;    // capacity - 1
180→}
181→
182→/**
183→ * RtArray — Contiguous mutable array.
184→ * Self-contained, no interpreter dependency.
185→ */
186→struct RtArray {
187→    Value* items;
188→    usz length;
189→    usz capacity;
190→}
