192→// =============================================================================
193→// SECTION 2: RUNTIME INITIALIZATION (Region-Based)
194→// =============================================================================
195→
196→/**
197→ * Thread-local current region for allocations.
198→ * Objects are allocated in this region by default.
199→ */
200→tlocal main::RegionHandle g_current_region;
201→
202→/**
203→ * Thread-local root region for global definitions.
204→ * Global `define`s allocate here so they outlive function calls.
205→ */
206→tlocal main::RegionHandle g_root_region;
207→
208→/**
209→ * Initialize the runtime with region-based memory management.
210→ * Must be called once per thread before any runtime operations.
211→ */
212→fn void rt_init() {
213→    main::thread_registry_init();
214→    g_root_region = main::thread_root_region();
215→    g_current_region = g_root_region;
216→}
217→
218→/**
219→ * Shutdown the runtime and release all regions.
220→ * Call before thread exit.
221→ */
222→fn void rt_shutdown() {
223→    main::thread_registry_shutdown();
224→}
225→
226→/**
227→ * Push a new frame region for function calls that create closures.
228→ * Objects allocated in this frame will be promoted to the parent
229→ * if they escape (via write barriers).
230→ *
231→ * @return Handle to the new frame region
232→ */
233→fn main::RegionHandle rt_push_frame() {
234→    main::RegionHandle child = main::create_region(g_current_region);
235→    g_current_region = child;
236→    return child;
237→}
238→
239→/**
240→ * Pop a frame region after a function call completes.
241→ * Escaped objects are automatically promoted to the parent region.
242→ *
243→ * @param frame The frame to pop (for verification)
244→ */
245→fn void rt_pop_frame(main::RegionHandle frame) {
246→    // Restore parent as current region
247→    main::RegionRegistry* reg = main::thread_registry();
248→    usz idx = (usz)(uint)frame.region_id;
249→    main::Region* region = &reg.region_storage[idx];
250→
251→    // Get parent region handle
252→    if ((uint)region.parent != (uint)main::NO_PARENT) {
253→        g_current_region = {
254→            .region_id = region.parent,
255→            .generation = reg.region_generations[(usz)(uint)region.parent]
256→        };
257→    } else {
258→        g_current_region = g_root_region;
259→    }
260→
261→    // Release the frame (may trigger promotion of escaped objects)
262→    main::release_region(frame);
263→}
264→
265→/**
266→ * Get the current allocation region.
267→ */
268→fn main::RegionHandle rt_current_region() @inline {
269→    return g_current_region;
270→}
271→
272→/**
273→ * Get the root region for global allocations.
274→ */
275→fn main::RegionHandle rt_root_region() @inline {
276→    return g_root_region;
277→}
278→
279→/**
280→ * Set the current allocation region.
281→ * Used when allocating in a specific region.
282→ */
283→fn void rt_set_current_region(main::RegionHandle region) @inline {
284→    g_current_region = region;
285→}
