473→// =============================================================================
474→// SECTION 3b: NATIVE DICT/ARRAY — HASH AND CRUD INTERNALS
475→// =============================================================================
476→
477→/**
478→ * FNV-1a hash for byte sequences.
479→ */
480→fn uint rt_fnv1a(char[] data) {
481→    uint h = 2166136261;
482→    for (usz i = 0; i < data.len; i++) { h ^= (uint)data[i]; h *= 16777619; }
483→    return h;
484→}
485→
486→/**
487→ * Murmur finalizer for integer-like keys.
488→ */
489→fn uint rt_murmur(uint h) {
490→    h ^= h >> 16; h *= 0x85ebca6b; h ^= h >> 13; h *= 0xc2b2ae35; h ^= h >> 16;
491→    return h;
492→}
493→
494→/**
495→ * Hash a runtime Value for use as dict key.
496→ */
497→fn uint rt_hash_key(Value key) {
498→    switch (key.tag) {
499→        case V_INT:    return rt_murmur((uint)key.int_val);
500→        case V_DOUBLE: return rt_murmur((uint)(long)key.double_val);

500→        case V_DOUBLE: return rt_murmur((uint)(long)key.double_val);
501→        case V_STRING:
502→            StringData* s = main::dereference_as(StringData, key.str_handle);
503→            return rt_fnv1a(s.chars[:s.len]);
504→        case V_SYMBOL:
505→            SymbolData* sym = main::dereference_as(SymbolData, key.sym_handle);
506→            return rt_fnv1a(sym.chars[:sym.len]);
507→        case V_TRUE:   return rt_murmur(1);
508→        case V_FALSE:  return rt_murmur(0);
509→        case V_NIL:    return 0;
510→        default:       return 0;
511→    }
512→}
513→
514→/**
515→ * Check if a hash entry slot is empty (key tag == V_NIL with no actual nil key stored).
516→ * We use a sentinel: empty slots have key.tag == V_NIL AND value.tag == V_NIL.
517→ * Actual nil keys are stored with a non-nil value sentinel.
518→ */
519→fn bool rtmap_slot_empty(RtHashEntry* entry) {
520→    // An entry is empty if key.tag is V_NIL
521→    // We don't support nil as a dict key (matching interpreter behavior)
522→    return entry.key.tag == V_NIL;
523→}
524→
525→/**
526→ * Check if two runtime Values are equal for key comparison.
527→ */
528→fn bool rt_key_equal(Value a, Value b) {
529→    if (a.tag != b.tag) {
530→        // Cross-type numeric comparison
531→        if ((a.tag == V_INT || a.tag == V_DOUBLE) && (b.tag == V_INT || b.tag == V_DOUBLE)) {
532→            return rt_to_double(a) == rt_to_double(b);
533→        }
534→        return false;
535→    }
536→    switch (a.tag) {
537→        case V_INT:    return a.int_val == b.int_val;
538→        case V_DOUBLE: return a.double_val == b.double_val;
539→        case V_STRING:
540→            StringData* sa = main::dereference_as(StringData, a.str_handle);
541→            StringData* sb = main::dereference_as(StringData, b.str_handle);
542→            if (sa.len != sb.len) return false;
543→            for (usz i = 0; i < sa.len; i++) {
544→                if (sa.chars[i] != sb.chars[i]) return false;
545→            }
546→            return true;
547→        case V_SYMBOL:
548→            SymbolData* sya = main::dereference_as(SymbolData, a.sym_handle);
549→            SymbolData* syb = main::dereference_as(SymbolData, b.sym_handle);
550→            if (sya.len != syb.len) return false;
551→            for (usz i = 0; i < sya.len; i++) {
552→                if (sya.chars[i] != syb.chars[i]) return false;
553→            }
554→            return true;
555→        case V_TRUE:   return true;
556→        case V_FALSE:  return true;
557→        case V_NIL:    return true;
558→        default:       return false;
559→    }
560→}
561→
562→/**
563→ * Create a new RtHashMap with given capacity (must be power of 2).
564→ */
565→fn RtHashMap* rtmap_new(uint capacity) {
566→    RtHashMap* m = (RtHashMap*)mem::malloc(RtHashMap.sizeof);
567→    m.capacity = capacity;
568→    m.count = 0;
569→    m.mask = capacity - 1;
570→    m.entries = (RtHashEntry*)mem::malloc(RtHashEntry.sizeof * capacity);
571→    for (uint i = 0; i < capacity; i++) {
572→        m.entries[i].key.tag = V_NIL;
573→        m.entries[i].value.tag = V_NIL;
574→    }
575→    return m;
576→}
577→
578→/**
579→ * Grow a hash map by doubling capacity and rehashing.
580→ */
581→fn void rtmap_grow(RtHashMap* m) {
582→    uint old_cap = m.capacity;
583→    RtHashEntry* old_entries = m.entries;
584→    uint new_cap = old_cap * 2;
585→    uint new_mask = new_cap - 1;
586→
587→    RtHashEntry* new_entries = (RtHashEntry*)mem::malloc(RtHashEntry.sizeof * new_cap);
588→    for (uint i = 0; i < new_cap; i++) {
589→        new_entries[i].key.tag = V_NIL;
590→        new_entries[i].value.tag = V_NIL;
591→    }
592→
593→    m.entries = new_entries;
594→    m.capacity = new_cap;
595→    m.mask = new_mask;
596→    m.count = 0;
597→
598→    for (uint i = 0; i < old_cap; i++) {
599→        if (!rtmap_slot_empty(&old_entries[i])) {
600→            // Re-insert into new table
601→            uint h = rt_hash_key(old_entries[i].key) & new_mask;
602→            for (uint j = 0; j < new_cap; j++) {
603→                uint idx = (h + j) & new_mask;
604→                if (rtmap_slot_empty(&new_entries[idx])) {
605→                    new_entries[idx] = old_entries[i];
606→                    m.count++;
607→                    break;
608→                }
609→            }
610→        }
611→    }
612→    mem::free(old_entries);
613→}
614→
615→/**
616→ * Get value for key. Returns pointer to value or null if not found.
617→ */
618→fn Value* rtmap_get(RtHashMap* m, Value key) {
619→    uint h = rt_hash_key(key) & m.mask;
620→    for (uint i = 0; i < m.capacity; i++) {
621→        uint idx = (h + i) & m.mask;
622→        RtHashEntry* entry = &m.entries[idx];
623→        if (rtmap_slot_empty(entry)) return null;
624→        if (rt_key_equal(entry.key, key)) return &entry.value;
625→    }
626→    return null;
627→}
628→
629→/**
630→ * Set key-value pair. Grows at 70% load.
631→ */
632→fn void rtmap_set(RtHashMap* m, Value key, Value value) {
633→    if (m.count * 10 >= m.capacity * 7) {
634→        rtmap_grow(m);
635→    }
636→
637→    uint h = rt_hash_key(key) & m.mask;
638→    for (uint i = 0; i < m.capacity; i++) {
639→        uint idx = (h + i) & m.mask;
640→        RtHashEntry* entry = &m.entries[idx];
641→        if (rtmap_slot_empty(entry)) {
642→            entry.key = key;
643→            entry.value = value;
644→            m.count++;
645→            return;
646→        }
647→        if (rt_key_equal(entry.key, key)) {
648→            entry.value = value;
649→            return;
650→        }
651→    }
652→}
