654→/**
655→ * Remove key from map using backward-shift deletion.
656→ */
657→fn bool rtmap_remove(RtHashMap* m, Value key) {
658→    uint h = rt_hash_key(key) & m.mask;
659→    for (uint i = 0; i < m.capacity; i++) {
660→        uint idx = (h + i) & m.mask;
661→        RtHashEntry* entry = &m.entries[idx];
662→        if (rtmap_slot_empty(entry)) return false;
663→        if (rt_key_equal(entry.key, key)) {
664→            // Backward shift delete
665→            uint j = idx;
666→            for (;;) {
667→                uint next = (j + 1) & m.mask;
668→                if (rtmap_slot_empty(&m.entries[next])) break;
669→                uint natural = rt_hash_key(m.entries[next].key) & m.mask;
670→                bool should_move;
671→                if (j < next) {
672→                    should_move = natural <= j || natural > next;
673→                } else {
674→                    should_move = natural <= j && natural > next;
675→                }
676→                if (!should_move) break;
677→                m.entries[j] = m.entries[next];
678→                j = next;
679→            }
680→            m.entries[j].key.tag = V_NIL;
681→            m.entries[j].value.tag = V_NIL;
682→            m.count--;
683→            return true;
684→        }
685→    }
686→    return false;
687→}
