815→/**
816→ * Apply a function to a cons-list of arguments.
817→ * Handles variadic closures, primitives, and curried application.
818→ * This is the multi-arg equivalent of rt_invoke.
819→ * Includes trampoline for TCO on the final result.
820→ */
821→fn Value rt_apply_multi(Value func, Value arg_list, long argc) {
822→    if (argc == 0) {
823→        // Zero-arg call
824→        return rt_invoke(func, make_nil());
825→    }
826→
827→    // Variadic closure: pass ALL args as a list directly
828→    if (func.tag == V_CLOSURE && func.closure_val.is_variadic) {
829→        Value result = func.closure_val.invoke(func.closure_val.data, arg_list);
830→        // Trampoline for TCO
831→        while (result.tag == V_THUNK) {
832→            Value* thunk_arg = main::dereference_as(Value, result.thunk_val.arg);
833→            result = result.thunk_val.invoke(result.thunk_val.data, *thunk_arg);
834→        }
835→        return result;
836→    }
837→
838→    if (argc == 1) {
839→        // Single arg: extract car and invoke
840→        if (arg_list.tag == V_CONS) {
841→            Value* car = main::dereference_as(Value, arg_list.cons_val.car);
842→            return rt_invoke(func, *car);
843→        }
844→        return rt_invoke(func, make_nil());
845→    }
846→
847→    // Multi-arg: apply one at a time (currying)
848→    // Use rt_invoke_once for intermediate applications (no trampoline bounce),
849→    // use rt_invoke for the last arg (with trampoline for TCO).
850→    Value result = func;
851→    Value current = arg_list;
852→    for (long i = 0; i < argc; i++) {
853→        if (current.tag != V_CONS) break;
854→        Value* car = main::dereference_as(Value, current.cons_val.car);
855→
856→        // Check if intermediate result became a variadic closure (e.g., after currying fixed params)
857→        if (result.tag == V_CLOSURE && result.closure_val.is_variadic) {
858→            // Pass remaining args as list
859→            Value remaining = current;
860→            Value vr = result.closure_val.invoke(result.closure_val.data, remaining);
861→            while (vr.tag == V_THUNK) {
862→                Value* ta = main::dereference_as(Value, vr.thunk_val.arg);
863→                vr = vr.thunk_val.invoke(vr.thunk_val.data, *ta);
864→            }
865→            return vr;
866→        }
867→
868→        if (i == argc - 1) {
869→            // Last arg: use full trampoline
870→            result = rt_invoke(result, *car);
871→        } else {
872→            // Intermediate: no trampoline (partial app shouldn't return thunks)
873→            result = rt_invoke_once(result, *car);
874→        }
875→        Value* cdr = main::dereference_as(Value, current.cons_val.cdr);
876→        current = *cdr;
877→    }
878→    return result;
879→}
