881→/**
882→ * Check if two values are equal.
883→ */
884→fn bool rt_values_equal(Value a, Value b, usz depth = 0) {
885→    if (depth >= 256) return false;  // Guard against circular structures
886→    // Mixed int/double comparison
887→    if (rt_is_number(a) && rt_is_number(b)) {
888→        return rt_to_double(a) == rt_to_double(b);
889→    }
890→    if (a.tag != b.tag) return false;
891→
892→    switch (a.tag) {
893→        case V_NIL:
894→            return true;
895→        case V_TRUE:
896→            return true;
897→        case V_FALSE:
898→            return true;
899→        case V_INT:
900→            return a.int_val == b.int_val;
901→        case V_DOUBLE:
902→            return a.double_val == b.double_val;
903→        case V_STRING:
904→            StringData* sa = main::dereference_as(StringData, a.str_handle);
905→            StringData* sb = main::dereference_as(StringData, b.str_handle);
906→            if (sa.len != sb.len) return false;
907→            for (usz i = 0; i < sa.len; i++) {
908→                if (sa.chars[i] != sb.chars[i]) return false;
909→            }
910→            return true;
911→        case V_SYMBOL:
912→            SymbolData* sya = main::dereference_as(SymbolData, a.sym_handle);
913→            SymbolData* syb = main::dereference_as(SymbolData, b.sym_handle);
914→            if (sya.len != syb.len) return false;
915→            for (usz i = 0; i < sya.len; i++) {
916→                if (sya.chars[i] != syb.chars[i]) return false;
917→            }
918→            return true;
919→        case V_CONS:
920→            Value* car_a = main::dereference_as(Value, a.cons_val.car);
921→            Value* cdr_a = main::dereference_as(Value, a.cons_val.cdr);
922→            Value* car_b = main::dereference_as(Value, b.cons_val.car);
923→            Value* cdr_b = main::dereference_as(Value, b.cons_val.cdr);
924→            return rt_values_equal(*car_a, *car_b, depth + 1) && rt_values_equal(*cdr_a, *cdr_b, depth + 1);
925→        case V_DICT:
926→            return a.dict_val == b.dict_val;  // Pointer equality for mutable containers
927→        case V_ARRAY:
928→            if (a.array_val == null || b.array_val == null) return a.array_val == b.array_val;
929→            if (a.array_val.length != b.array_val.length) return false;
930→            for (usz i = 0; i < a.array_val.length; i++) {
931→                if (!rt_values_equal(a.array_val.items[i], b.array_val.items[i], depth + 1)) return false;
932→            }
933→            return true;
934→        case V_INTERP_REF:
935→            return a.interp_ref == b.interp_ref;
936→        default:
937→            return false;
938→    }
939→}
