1192→            io::print("nil");
1193→        case V_TRUE:
1194→            io::print("true");
1195→        case V_FALSE:
1196→            io::print("false");
1197→        case V_INT:
1198→            io::printf("%d", v.int_val);
1199→        case V_DOUBLE:
1200→            double dv = v.double_val;
1201→            if (dv != dv) {
1202→                io::print("+nan.0");
1203→            } else if (dv == 1.0/0.0) {
1204→                io::print("+inf.0");
1205→            } else if (dv == -1.0/0.0) {
1206→                io::print("-inf.0");
1207→            } else {
1208→                io::printf("%.15g", dv);
1209→                // If printf didn't include a decimal point, add .0
1210→                char[64] dbuf;
1211→                char[] dslice = io::bprintf(&dbuf, "%.15g", dv)!!;
1212→                bool has_dot = false;
1213→                for (usz di = 0; di < dslice.len; di++) {
1214→                    if (dslice[di] == '.' || dslice[di] == 'e' || dslice[di] == 'E') { has_dot = true; break; }
1215→                }
1216→                if (!has_dot) io::print(".0");
1217→            }
1218→        case V_STRING:
1219→            StringData* str = main::dereference_as(StringData, v.str_handle);
1220→            io::printf("\"%s\"", (ZString)&str.chars);
1221→        case V_SYMBOL:
1222→            SymbolData* sym = main::dereference_as(SymbolData, v.sym_handle);
1223→            io::printf("%s", (ZString)&sym.chars);
1224→        case V_CONS:
1225→            io::print("(");
1226→            Value* car = main::dereference_as(Value, v.cons_val.car);
1227→            rt_print_value(*car);
1228→            Value* cdr = main::dereference_as(Value, v.cons_val.cdr);
1229→            Value rest = *cdr;
1230→            while (rest.tag == V_CONS) {
1231→                io::print(" ");
1232→                Value* rest_car = main::dereference_as(Value, rest.cons_val.car);
1233→                rt_print_value(*rest_car);
1234→                Value* rest_cdr = main::dereference_as(Value, rest.cons_val.cdr);
1235→                rest = *rest_cdr;
1236→            }
1237→            if (rest.tag != V_NIL) {
1238→                io::print(" . ");
1239→                rt_print_value(rest);
1240→            }
1241→            io::print(")");
1242→        case V_CLOSURE:
1243→            io::print("#<closure>");
1244→        case V_PRIM:
1245→            io::print("#<primitive>");
1246→        case V_PRIM_UNARY:
1247→            io::print("#<primitive-unary>");
1248→        case V_PARTIAL:
1249→            io::print("#<partial>");
1250→        case V_DICT:
1251→            io::print("{");
1252→            RtHashMap* dm = v.dict_val;
1253→            bool dfirst = true;
1254→            for (uint di = 0; di < dm.capacity; di++) {
1255→                if (!rtmap_slot_empty(&dm.entries[di])) {
1256→                    if (!dfirst) io::print(" ");
1257→                    dfirst = false;
1258→                    rt_print_value(dm.entries[di].key);
1259→                    io::print(" ");
1260→                    rt_print_value(dm.entries[di].value);
1261→                }
1262→            }
1263→            io::print("}");
1264→        case V_ARRAY:
1265→            io::print("[");
1266→            RtArray* arr = v.array_val;
1267→            for (usz ai = 0; ai < arr.length; ai++) {
1268→                if (ai > 0) io::print(" ");
1269→                rt_print_value(arr.items[ai]);
1270→            }
1271→            io::print("]");
1272→        case V_INTERP_REF:
1273→            io::print("#<interp-ref>");
1274→        default:
1275→            io::print("#<unknown>");
1276→    }
1277→}
