1294→/**
1295→ * Mark a Value's handles as escaped if they cross region boundaries.
1296→ * Call this when storing a Value into a closure or other cross-region structure.
1297→ *
1298→ * @param storing_region The region where the Value is being stored
1299→ * @param v The Value being stored
1300→ */
1301→fn void rt_write_barrier_value(main::RegionId storing_region, Value v) {
1302→    switch (v.tag) {
1303→        case V_STRING:
1304→            main::write_barrier(storing_region, v.str_handle);
1305→        case V_SYMBOL:
1306→            main::write_barrier(storing_region, v.sym_handle);
1307→        case V_CONS:
1308→            main::write_barrier(storing_region, v.cons_val.car);
1309→            main::write_barrier(storing_region, v.cons_val.cdr);
1310→        case V_PARTIAL:
1311→            main::write_barrier(storing_region, v.partial_val.first_arg);
1312→        default:
1313→            // Immediates don't need write barriers
1314→            return;
1315→    }
1316→}
