1394→/**
1395→ * Substring — 3-arg curried primitive: (substring str start end)
1396→ * The compiler curries as (((substring str) start) end).
1397→ * Step 1: (substring str) → partial(rt_substring_step1, str)
1398→ * Step 2: (partial start) → rt_substring_step1(str, start) → closure expecting end
1399→ * Step 3: (closure end) → performs the actual substring extraction
1400→ */
1401→struct SubstringCapture {
1402→    Value str;
1403→    Value start;
1404→}
1405→
1406→fn Value rt_substring_end_fn(void* data, Value end_val) {
1407→    SubstringCapture* cap = (SubstringCapture*)data;
1408→    if (cap.str.tag != V_STRING || cap.start.tag != V_INT) return make_nil();
1409→    if (end_val.tag != V_INT) return make_nil();
1410→
1411→    StringData* s = main::dereference_as(StringData, cap.str.str_handle);
1412→    usz cp_count = rt_utf8_strlen(s.chars[:s.len]);
1413→    long start = cap.start.int_val;
1414→    long end = end_val.int_val;
1415→
1416→    // Bounds checking — codepoint-based
1417→    if (start < 0) start += (long)cp_count;
1418→    if (start < 0) start = 0;
1419→    if (start > (long)cp_count) start = (long)cp_count;
1420→    if (end < 0) end += (long)cp_count;
1421→    if (end < 0) end = 0;
1422→    if (end > (long)cp_count) end = (long)cp_count;
1423→    if (end < start) end = start;
1424→
1425→    // Convert codepoint indices to byte offsets
1426→    usz byte_start = rt_utf8_byte_offset(s.chars[:s.len], (usz)start);
1427→    usz byte_end = rt_utf8_byte_offset(s.chars[:s.len], (usz)end);
1428→
1429→    StringData result;
1430→    usz len = byte_end - byte_start;
1431→    if (len > 4095) len = 4095;
1432→    for (usz i = 0; i < len; i++) {
1433→        result.chars[i] = s.chars[byte_start + i];
1434→    }
1435→    result.chars[len] = 0;
1436→    result.len = len;
1437→
1438→    Value v;
1439→    v.tag = V_STRING;
1440→    v.str_handle = main::allocate_in(g_current_region, StringData, result);
1441→    return v;
1442→}
1443→
1444→fn Value rt_substring_step1(Value str, Value start_v) {
1445→    // Create a closure capturing str and start, expecting end
1446→    SubstringCapture* cap = (SubstringCapture*)mem::malloc(SubstringCapture.sizeof);
1447→    cap.str = str;
1448→    cap.start = start_v;
1449→    return make_closure(cap, &rt_substring_end_fn);
1450→}
1451→
1452→fn Value rt_string_split(Value str, Value sep) {
1453→    if (str.tag != V_STRING || sep.tag != V_STRING) return make_nil();
1454→    StringData* s = main::dereference_as(StringData, str.str_handle);
1455→    StringData* d = main::dereference_as(StringData, sep.str_handle);
1456→    if (d.len == 0) return make_nil();
1457→
1458→    usz dlen = d.len;
1459→    Value result = make_nil();
1460→
1461→    // First pass: count delimiter matches to determine segment count
1462→    usz seg_count = 0;
1463→    {
1464→        usz pos = 0;
1465→        while (pos + dlen <= s.len) {
1466→            bool match = true;
1467→            for (usz k = 0; k < dlen; k++) {
1468→                if (s.chars[pos + k] != d.chars[k]) {
1469→                    match = false;
1470→                    break;
1471→                }
1472→            }
1473→            if (match) { seg_count++; pos += dlen; }
1474→            else { pos++; }
1475→        }
1476→    }
1477→    seg_count++;  // final segment after last delimiter
1478→
1479→    // Allocate exact-size arrays via temp allocator
1480→    usz[] starts = mem::temp_array(usz, seg_count);
1481→    usz[] lens = mem::temp_array(usz, seg_count);
1482→
1483→    // Second pass: fill starts and lens
1484→    usz si = 0;
1485→    usz seg_start = 0;
1486→    usz pos = 0;
1487→    while (pos + dlen <= s.len) {
1488→        bool match = true;
1489→        for (usz k = 0; k < dlen; k++) {
1490→            if (s.chars[pos + k] != d.chars[k]) {
1491→                match = false;
1492→                break;
1493→            }
1494→        }
1495→        if (match) {
1496→            starts[si] = seg_start;
1497→            lens[si] = pos - seg_start;
1498→            si++;
1499→            pos += dlen;

1500→            seg_start = pos;
1501→        } else {
1502→            pos++;
1503→        }
1504→    }
1505→    // Final segment
1506→    starts[si] = seg_start;
1507→    lens[si] = s.len - seg_start;
1508→
1509→    // Build list in reverse order so cons produces correct order
1510→    for (usz i = seg_count; i > 0; i--) {
1511→        usz idx = i - 1;
1512→        usz start = starts[idx];
1513→        usz len = lens[idx];
1514→        if (len > 4095) { len = 4095; }
1515→
1516→        StringData part;
1517→        for (usz j = 0; j < len; j++) {
1518→            part.chars[j] = s.chars[start + j];
1519→        }
1520→        part.chars[len] = 0;
1521→        part.len = len;
1522→
1523→        Value part_val;
1524→        part_val.tag = V_STRING;
1525→        part_val.str_handle = main::allocate_in(g_current_region, StringData, part);
1526→        result = rt_cons(part_val, result);
1527→    }
1528→
1529→    return result;
1530→}
