1539→fn Value rt_string_to_list(Value a, Value _unused) {
1540→    if (a.tag != V_STRING) return make_nil();
1541→    StringData* s = main::dereference_as(StringData, a.str_handle);
1542→
1543→    // First pass: count codepoints
1544→    usz cp_count = 0;
1545→    usz pos = 0;
1546→    while (pos < s.len) {
1547→        usz cplen = rt_utf8_cplen(s.chars[pos]);
1548→        if (pos + cplen > s.len) cplen = s.len - pos;
1549→        pos += cplen;
1550→        cp_count++;
1551→    }
1552→
1553→    if (cp_count == 0) return make_nil();
1554→
1555→    // Allocate exact-size arrays via temp allocator
1556→    usz[] offsets = mem::temp_array(usz, cp_count);
1557→    usz[] cp_lens = mem::temp_array(usz, cp_count);
1558→
1559→    // Second pass: fill offsets and lens
1560→    pos = 0;
1561→    for (usz i = 0; i < cp_count; i++) {
1562→        offsets[i] = pos;
1563→        usz cplen = rt_utf8_cplen(s.chars[pos]);
1564→        if (pos + cplen > s.len) cplen = s.len - pos;
1565→        cp_lens[i] = cplen;
1566→        pos += cplen;
1567→    }
1568→
1569→    // Build list in reverse order
1570→    Value result = make_nil();
1571→    for (isz i = (isz)cp_count - 1; i >= 0; i--) {
1572→        usz off = offsets[(usz)i];
1573→        usz clen = cp_lens[(usz)i];
1574→        StringData ch;
1575→        for (usz j = 0; j < clen; j++) ch.chars[j] = s.chars[off + j];
1576→        ch.chars[clen] = 0;
1577→        ch.len = clen;
1578→
1579→        Value char_val;
1580→        char_val.tag = V_STRING;
1581→        char_val.str_handle = main::allocate_in(g_current_region, StringData, ch);
1582→        result = rt_cons(char_val, result);
1583→    }
1584→    return result;
1585→}
