1587→fn Value rt_list_to_string(Value a, Value _unused) {
1588→    StringData result;
1589→    usz pos = 0;
1590→
1591→    Value current = a;
1592→    while (current.tag == V_CONS) {
1593→        Value* elem = main::dereference_as(Value, current.cons_val.car);
1594→        if (elem.tag == V_STRING) {
1595→            StringData* s = main::dereference_as(StringData, elem.str_handle);
1596→            for (usz i = 0; i < s.len && pos < 4095; i++) {
1597→                result.chars[pos++] = s.chars[i];
1598→            }
1599→        } else if (elem.tag == V_INT) {
1600→            if (pos < 4095) {
1601→                result.chars[pos++] = (char)elem.int_val;
1602→            }
1603→        }
1604→        Value* next = main::dereference_as(Value, current.cons_val.cdr);
1605→        current = *next;
1606→    }
1607→
1608→    result.chars[pos] = 0;
1609→    result.len = pos;
1610→
1611→    Value v;
1612→    v.tag = V_STRING;
1613→    v.str_handle = main::allocate_in(g_current_region, StringData, result);
1614→    return v;
1615→}
