1729→fn Value rt_type_of(Value a, Value _unused) {
1730→    switch (a.tag) {
1731→        case V_INT:          return make_symbol("Int");
1732→        case V_DOUBLE:       return make_symbol("Double");
1733→        case V_STRING:       return make_symbol("String");
1734→        case V_SYMBOL:       return make_symbol("Symbol");
1735→        case V_CONS:         return make_symbol("List");
1736→        case V_CLOSURE:      return make_symbol("Closure");
1737→        case V_PRIM:         return make_symbol("Closure");
1738→        case V_PRIM_UNARY:   return make_symbol("Closure");
1739→        case V_PARTIAL:      return make_symbol("Closure");
