1898→        return rt_list_nth(collection, (usz)index.int_val);
1899→    }
1900→    if (collection.tag == V_STRING && index.tag == V_INT) {
1901→        StringData* s = main::dereference_as(StringData, collection.str_handle);
1902→        usz idx = (usz)index.int_val;
1903→        if (idx < s.len) {
