2092→/**
2093→ * rt_compiled_handle — Evaluate body with effect handlers installed.
2094→ * tags[i] is V_SYMBOL, handlers[i] is V_CLOSURE receiving (cons k arg).
2095→ */
2096→fn Value rt_compiled_handle(Value* tags, Value* handlers, usz clause_count, Value body_closure) {
2097→    if (rt_handler_count >= RT_MAX_HANDLERS) {
2098→        io::printfn("Error: handler stack overflow");
2099→        return make_nil();
2100→    }
2101→
2102→    RtEffectHandler* h = &rt_handler_stack[rt_handler_count];
2103→    h.clause_count = clause_count;
2104→    h.body_closure = body_closure;
2105→    for (usz i = 0; i < clause_count && i < RT_MAX_CLAUSES; i++) {
2106→        h.clauses[i].tag = tags[i];
2107→        h.clauses[i].handler_closure = handlers[i];
2108→    }
2109→
2110→    usz saved_perform_ctr = rt_eff_perform_ctr;
2111→    rt_eff_perform_ctr = 0;
2112→    rt_handler_count++;
2113→
2114→    Value result = body_closure.closure_val.invoke(body_closure.closure_val.data, make_nil());
2115→    while (result.tag == V_THUNK) {
2116→        Value* ta = main::dereference_as(Value, result.thunk_val.arg);
2117→        result = result.thunk_val.invoke(result.thunk_val.data, *ta);
2118→    }
2119→
2120→    rt_eff_perform_ctr = saved_perform_ctr;
2121→
2122→    if (rt_effect_occurred) {
2123→        rt_effect_occurred = false;
2124→        return rt_effect_result_val;
2125→    }
2126→
2127→    rt_handler_count--;
2128→    return result;
2129→}
2130→
2131→/**
2132→ * rt_compiled_perform — Dispatch an effect.
2133→ * Searches handler stack, captures continuation, calls handler.
2134→ * I/O fast path when no handler installed.
2135→ */
2136→fn Value rt_compiled_perform(Value tag, Value arg) {
2137→    // REPLAY CHECK
2138→    if (rt_cont_sub && rt_cont_is_eff) {
2139→        // Check if tags match
2140→        if (tag.tag == V_SYMBOL && rt_cont_eff_tag.tag == V_SYMBOL) {
2141→            SymbolData* t1 = main::dereference_as(SymbolData, tag.sym_handle);
2142→            SymbolData* t2 = main::dereference_as(SymbolData, rt_cont_eff_tag.sym_handle);
2143→            bool match = (t1.len == t2.len);
2144→            if (match) {
2145→                for (usz c = 0; c < t1.len; c++) {
2146→                    if (t1.chars[c] != t2.chars[c]) { match = false; break; }
2147→                }
2148→            }
2149→            if (match) {
2150→                usz current = rt_eff_perform_ctr;
2151→                rt_eff_perform_ctr++;
2152→                if (current < rt_cont_target_perform) {
2153→                    return rt_eff_prior[current];
2154→                }
2155→                if (current == rt_cont_target_perform) {
2156→                    rt_cont_sub = false;
2157→                    if (current < RT_MAX_PRIOR) {
2158→                        rt_eff_prior[current] = rt_cont_sub_val;
2159→                    }
2160→                    return rt_cont_sub_val;
2161→                }
2162→            }
2163→        }
2164→    }
2165→
2166→    // Search handler stack for matching handler
2167→    for (isz i = (isz)rt_handler_count - 1; i >= 0; i--) {
2168→        RtEffectHandler* h = &rt_handler_stack[(usz)i];
2169→        for (usz j = 0; j < h.clause_count; j++) {
2170→            // Compare tag symbols
2171→            if (tag.tag != V_SYMBOL || h.clauses[j].tag.tag != V_SYMBOL) continue;
2172→            SymbolData* t1 = main::dereference_as(SymbolData, tag.sym_handle);
2173→            SymbolData* t2 = main::dereference_as(SymbolData, h.clauses[j].tag.sym_handle);
2174→            bool match = (t1.len == t2.len);
2175→            if (match) {
2176→                for (usz c = 0; c < t1.len; c++) {
2177→                    if (t1.chars[c] != t2.chars[c]) { match = false; break; }
2178→                }
2179→            }
2180→            if (!match) continue;
2181→
2182→            // Found matching handler — capture continuation
2183→            RtCapturedCont* cc = (RtCapturedCont*)mem::malloc(RtCapturedCont.sizeof);
2184→            cc.body_closure = h.body_closure;
2185→            cc.is_effect = true;
2186→            cc.effect_tag = tag;
2187→            cc.handler_copy = *h;
2188→            cc.has_handler = true;
2189→            cc.perform_index = rt_eff_perform_ctr;
2190→            cc.prior_count = rt_eff_perform_ctr;
2191→            for (usz pi = 0; pi < cc.prior_count && pi < RT_MAX_PRIOR; pi++) {
2192→                cc.prior_results[pi] = rt_eff_prior[pi];
2193→            }
2194→            rt_eff_perform_ctr++;
2195→
2196→            Value k_val = make_closure((void*)cc, &invoke_compiled_continuation);
2197→
2198→            rt_handler_count--;
2199→
2200→            // Call handler with (cons k arg)
2201→            Value pair = rt_cons(k_val, arg);
2202→            Value handler_result = h.clauses[j].handler_closure.closure_val.invoke(
2203→                h.clauses[j].handler_closure.closure_val.data, pair);
2204→            while (handler_result.tag == V_THUNK) {
2205→                Value* ta = main::dereference_as(Value, handler_result.thunk_val.arg);
2206→                handler_result = handler_result.thunk_val.invoke(handler_result.thunk_val.data, *ta);
2207→            }
2208→
2209→            rt_effect_occurred = true;
2210→            rt_effect_result_val = handler_result;
2211→            return handler_result;
2212→        }
2213→    }
2214→
2215→    // I/O fast path: no handler found → direct I/O
2216→    if (tag.tag == V_SYMBOL) {
2217→        SymbolData* ts = main::dereference_as(SymbolData, tag.sym_handle);
2218→        char[] tn = ts.chars[:ts.len];
2219→        if (rt_sym_eq(tn, "io/print")) {
2220→            rt_print_value(arg);
2221→            return make_nil();
2222→        } else if (rt_sym_eq(tn, "io/println")) {
2223→            rt_print_value(arg);
2224→            io::printn("");
2225→            return make_nil();
2226→        } else if (rt_sym_eq(tn, "io/display")) {
2227→            rt_print_value(arg);
2228→            return make_nil();
2229→        } else if (rt_sym_eq(tn, "io/newline")) {
2230→            io::printn("");
2231→            return make_nil();
2232→        } else if (rt_sym_eq(tn, "io/read-file")) {
2233→            return rt_read_file(arg, make_nil());
2234→        } else if (rt_sym_eq(tn, "io/write-file")) {
2235→            // arg should be (cons filename content)
2236→            if (arg.tag == V_CONS) {
2237→                Value* fname = main::dereference_as(Value, arg.cons_val.car);
2238→                Value* content = main::dereference_as(Value, arg.cons_val.cdr);
2239→                return rt_write_file(*fname, *content);
2240→            }
2241→            return make_nil();
2242→        } else if (rt_sym_eq(tn, "io/file-exists?")) {
2243→            return rt_file_exists(arg, make_nil());
2244→        } else if (rt_sym_eq(tn, "io/read-lines")) {
2245→            return rt_read_lines(arg, make_nil());
2246→        }
2247→    }
2248→
2249→    io::printfn("Error: unhandled effect in compiled code");
2250→    return make_nil();
2251→}
