2253→fn bool rt_sym_eq(char[] a, char[] b) @inline {
2254→    if (a.len != b.len) return false;
2255→    for (usz i = 0; i < a.len; i++) {
2256→        if (a[i] != b[i]) return false;
2257→    }
2258→    return true;
2259→}
