2261→/**
2262→ * invoke_compiled_continuation — Resume a captured continuation with a value.
2263→ * Wraps the replay mechanism as a ClosureFn for use as V_CLOSURE.
2264→ */
2265→fn Value invoke_compiled_continuation(void* data, Value arg) {
2266→    RtCapturedCont* cc = (RtCapturedCont*)data;
2267→    if (cc == null) {
2268→        io::printfn("Error: null continuation");
2269→        return make_nil();
2270→    }
2271→
2272→    rt_cont_sub_val = arg;
2273→    rt_cont_sub = true;
2274→    rt_cont_is_eff = cc.is_effect;
2275→    if (cc.is_effect) {
2276→        rt_cont_eff_tag = cc.effect_tag;
2277→    }
2278→
2279→    Value result;
2280→
2281→    if (cc.is_effect && cc.has_handler) {
2282→        // Reinstall handler for replay
2283→        if (rt_handler_count >= RT_MAX_HANDLERS) {
2284→            io::printfn("Error: handler stack overflow during continuation resume");
2285→            return make_nil();
2286→        }
2287→        rt_handler_stack[rt_handler_count] = cc.handler_copy;
2288→        rt_handler_stack[rt_handler_count].body_closure = cc.body_closure;
2289→        rt_handler_count++;
2290→
2291→        rt_cont_target_perform = cc.perform_index;
2292→        rt_eff_perform_ctr = 0;
2293→        for (usz i = 0; i < cc.prior_count && i < RT_MAX_PRIOR; i++) {
2294→            rt_eff_prior[i] = cc.prior_results[i];
2295→        }
2296→
2297→        // Replay body
2298→        result = cc.body_closure.closure_val.invoke(cc.body_closure.closure_val.data, make_nil());
2299→        while (result.tag == V_THUNK) {
2300→            Value* ta = main::dereference_as(Value, result.thunk_val.arg);
2301→            result = result.thunk_val.invoke(result.thunk_val.data, *ta);
2302→        }
2303→
2304→        if (rt_effect_occurred) {
2305→            rt_effect_occurred = false;
2306→            result = rt_effect_result_val;
2307→        } else {
2308→            rt_handler_count--;
2309→        }
2310→    } else {
2311→        // Shift continuation replay
2312→        rt_cont_target_shift = cc.shift_index;
2313→        rt_eff_shift_ctr = 0;
2314→        for (usz i = 0; i < cc.shift_prior_count && i < RT_MAX_PRIOR; i++) {
2315→            rt_shift_prior[i] = cc.shift_prior_results[i];
2316→        }
2317→
2318→        result = cc.body_closure.closure_val.invoke(cc.body_closure.closure_val.data, make_nil());
2319→        while (result.tag == V_THUNK) {
2320→            Value* ta = main::dereference_as(Value, result.thunk_val.arg);
2321→            result = result.thunk_val.invoke(result.thunk_val.data, *ta);
2322→        }
2323→    }
2324→
2325→    rt_cont_sub = false;
2326→    return result;
2327→}
