2333→fn Value rt_read_file(Value path, Value _unused) {
2334→    if (path.tag != V_STRING) return make_nil();
2335→    StringData* p = main::dereference_as(StringData, path.str_handle);
2336→
2337→    // Get path as slice
2338→    char[] path_slice = p.chars[:p.len];
2339→
2340→    // Use C3's file::load_temp to read entire file
2341→    if (try content = io::file::load_temp((String)path_slice)) {
2342→        usz len = content.len;
2343→        if (len > 4095) len = 4095;
2344→
2345→        StringData result;
2346→        for (usz i = 0; i < len; i++) {
2347→            result.chars[i] = content[i];
2348→        }
2349→        result.chars[len] = 0;
2350→        result.len = len;
2351→
2352→        Value v;
2353→        v.tag = V_STRING;
2354→        v.str_handle = main::allocate_in(g_current_region, StringData, result);
2355→        return v;
2356→    }
2357→    return make_nil();
2358→}
