2360→fn Value rt_write_file(Value path, Value content) {
2361→    if (path.tag != V_STRING || content.tag != V_STRING) return make_nil();
2362→    StringData* p = main::dereference_as(StringData, path.str_handle);
2363→    StringData* c = main::dereference_as(StringData, content.str_handle);
2364→
2365→    // Get path and content as slices
2366→    char[] path_slice = p.chars[:p.len];
2367→    char[] content_slice = c.chars[:c.len];
2368→
2369→    if (try file = io::file::open((String)path_slice, "w")) {
2370→        file.write(content_slice)!!;
2371→        file.close()!!;
2372→        return make_true();
2373→    }
2374→    return make_nil();
2375→}
