2377→fn Value rt_file_exists(Value path, Value _unused) {
2378→    if (path.tag != V_STRING) return make_nil();
2379→    StringData* p = main::dereference_as(StringData, path.str_handle);
2380→
2381→    // Get path as slice
2382→    char[] path_slice = p.chars[:p.len];
